changeSet.sql:
INSERT INTO dbo.user_role (user_id, role_id)
SELECT u.id, r.id FROM dbo.[user] u, dbo.role r
WHERE u.username = 'admin' AND r.name = 'ADMIN';

INSERT INTO dbo.user_role (user_id, role_id)
SELECT u.id, r.id FROM dbo.[user] u, dbo.role r
WHERE u.username = 'john_doe' AND r.name = 'CUSTOMER';

INSERT INTO dbo.user_role (user_id, role_id)
SELECT u.id, r.id FROM dbo.[user] u, dbo.role r
WHERE u.username = 'jane_smith' AND r.name = 'CUSTOMER';

rollback.sql:
DELETE ur FROM dbo.user_role ur
INNER JOIN dbo.[user] u ON ur.user_id = u.id
WHERE u.username IN ('admin', 'john_doe', 'jane_smith');

DELETE FROM dbo.[user] WHERE username IN ('admin', 'john_doe', 'jane_smith');
